"use client";

import { AuditTool } from "@/hooks/useAuditForm";
import { AI_TOOLS, PLANS } from "@/lib/constants";

interface AuditFormToolRowProps {
  tool: AuditTool;
  onUpdate: (updates: Partial<AuditTool>) => void;
  onRemove: () => void;
  canRemove: boolean;
}

export default function AuditFormToolRow({
  tool,
  onUpdate,
  onRemove,
  canRemove,
}: AuditFormToolRowProps) {
  const availablePlans =
    PLANS[tool.tool as keyof typeof PLANS] || PLANS.Other;

  return (
    <div className="grid grid-cols-12 gap-md items-end p-lg bg-surface border border-outline-variant/50 rounded-lg">
      {/* Tool Selection */}
      <div className="col-span-3 space-y-xs">
        <label className="text-[10px] font-black text-on-surface-variant uppercase tracking-wider">
          Tool
        </label>
        <select
          value={tool.tool}
          onChange={(e) => onUpdate({ tool: e.target.value })}
          className="w-full bg-surface-container-lowest border border-outline-variant rounded px-sm py-2 text-sm focus:ring-1 focus:ring-primary outline-none font-body-sm"
        >
          {AI_TOOLS.map((t) => (
            <option key={t.value} value={t.value}>
              {t.label}
            </option>
          ))}
        </select>
      </div>

      {/* Plan Selection */}
      <div className="col-span-3 space-y-xs">
        <label className="text-[10px] font-black text-on-surface-variant uppercase tracking-wider">
          Plan
        </label>
        <select
          value={tool.plan}
          onChange={(e) => onUpdate({ plan: e.target.value })}
          className="w-full bg-surface-container-lowest border border-outline-variant rounded px-sm py-2 text-sm focus:ring-1 focus:ring-primary outline-none font-body-sm"
        >
          {availablePlans.map((p) => (
            <option key={p.value} value={p.value}>
              {p.label}
            </option>
          ))}
        </select>
      </div>

      {/* Monthly Spend */}
      <div className="col-span-2 space-y-xs">
        <label className="text-[10px] font-black text-on-surface-variant uppercase tracking-wider">
          Spend ($)
        </label>
        <input
          type="number"
          min="0"
          step="0.01"
          value={tool.spend}
          onChange={(e) => onUpdate({ spend: parseFloat(e.target.value) || 0 })}
          placeholder="0"
          className="w-full bg-surface-container-lowest border border-outline-variant rounded px-sm py-2 text-sm focus:ring-1 focus:ring-primary outline-none font-body-sm"
        />
      </div>

      {/* Seats */}
      <div className="col-span-2 space-y-xs">
        <label className="text-[10px] font-black text-on-surface-variant uppercase tracking-wider">
          Seats
        </label>
        <input
          type="number"
          min="1"
          value={tool.seats}
          onChange={(e) => onUpdate({ seats: parseInt(e.target.value) || 1 })}
          placeholder="1"
          className="w-full bg-surface-container-lowest border border-outline-variant rounded px-sm py-2 text-sm focus:ring-1 focus:ring-primary outline-none font-body-sm"
        />
      </div>

      {/* Remove Button */}
      <div className="col-span-2 flex justify-end">
        <button
          onClick={onRemove}
          disabled={!canRemove}
          className={`px-md py-2 rounded text-sm font-semibold transition-all ${
            canRemove
              ? "bg-error/10 text-error hover:bg-error/20"
              : "bg-outline-variant/10 text-outline-variant cursor-not-allowed"
          }`}
        >
          <span className="material-symbols-outlined text-[18px]">delete</span>
        </button>
      </div>
    </div>
  );
}
